const resposta = $input.first().json.result || $input.first().json.resposta || '';
const respostaLower = resposta.toLowerCase();

// ForГ§a texto se tiver valor monetГЎrio, experience resource ou parcelamento
const temValorMonetario = /r\$\s*[\d.,]+/.test(respostaLower);
const temCabine = ['experience resource', 'cabin', 'interna', 'varanda', 'suГӯte', 'suite', 'yacht'].some(kw => respostaLower.includes(kw));
const temParcelamento = /\d+x/.test(respostaLower);

// ForГ§a texto se for uma listagem (itens numerados ou mГәltiplos bullet points)
const temListaNumerada = /\n\s*\d+[\.\)]\s/.test(resposta);
const temBullets = (resposta.match(/\n\s*[-вҖў*]\s/g) || []).length >= 2;
const temQuebrasMultiplas = (resposta.match(/\n/g) || []).length >= 4;

// ForГ§a texto se resposta for longa demais
const LIMITE_CHARS = 180;
const textoLongo = resposta.length > LIMITE_CHARS;

const forcarTexto = temValorMonetario || temCabine || temParcelamento
                  || temListaNumerada || temBullets || temQuebrasMultiplas
                  || textoLongo;

const enviarAudio = forcarTexto ? false : Math.random() < 0.5;

return [{
  json: {
    ...$input.first().json,
    enviarAudio
  }
}];

// в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
// в•‘  CODE NODE: Calcular Delays вҖ” Anatomia da Mensagem              в•‘
// в•‘  PosiГ§ГЈo: APГ“S o AI Agent que quebrou a mensagem                в•‘
// в•‘                                                                  в•‘
// в•‘  Input : JSON com array "mensagens" retornado pela LLM          в•‘
// в•‘  Output: Array de items, 1 por mensagem, com delay_ms calculado в•‘
// в•‘                                                                  в•‘
// в•‘  O nГі seguinte (SplitInBatches ou Loop) envia cada mensagem     в•‘
// в•‘  com o delay correspondente via Wait node ou setTimeout.        в•‘
// в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ

const raw = $input.first().json;

// в”Җв”Җ Parse defensivo do output da LLM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let mensagens = [];

if (raw.output) {
  // AI Agent node retorna em .output (string ou objeto)
  try {
    const parsed = typeof raw.output === 'string'
      ? JSON.parse(raw.output.replace(/```json|```/g, '').trim())
      : raw.output;
    mensagens = parsed.mensagens || [];
  } catch (e) {
    // Fallback: se a LLM nГЈo retornou JSON vГЎlido, enviar texto original como mensagem Гәnica
    mensagens = [{ texto: String(raw.output), tamanho: 'grande' }];
  }
} else if (raw.mensagens) {
  mensagens = raw.mensagens;
} else if (raw.text) {
  // Fallback para AI Agent que retorna em .text
  try {
    const parsed = JSON.parse(raw.text.replace(/```json|```/g, '').trim());
    mensagens = parsed.mensagens || [];
  } catch (e) {
    mensagens = [{ texto: String(raw.text), tamanho: 'grande' }];
  }
}

// в”Җв”Җ ValidaГ§ГЈo: se vazio, fallback в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
if (!mensagens || mensagens.length === 0) {
  return [{
    json: {
      texto: raw.respostaOriginal || raw.output || '[ERRO: sem mensagens]',
      tamanho: 'grande',
      delay_ms: 0,
      indice: 0,
      total: 1,
      primeira: true,
      ultima: true
    }
  }];
}

// в”Җв”Җ FГіrmula de delay (da Anatomia da Mensagem) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// delay_ms = clamp(700 + (chars*38) + (virgulas*180) + (pontos*280) + (quebras*450), 1000, 12000)
// + jitter de Вұ12%

function calcDelay(texto) {
  const chars    = texto.length;
  const virgulas = (texto.match(/,/g) || []).length;
  const pontos   = (texto.match(/[.!?;:]/g) || []).length;
  const quebras  = (texto.match(/\n/g) || []).length;

  const base = 700 + (chars * 38) + (virgulas * 180) + (pontos * 280) + (quebras * 450);
  const clamped = Math.max(1000, Math.min(12000, base));

  // Jitter Вұ12%
  const jitter = 1 + (Math.random() * 0.24 - 0.12);
  return Math.round(clamped * jitter);
}

// в”Җв”Җ Montar saГӯda: 1 item por mensagem в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const result = mensagens.map((msg, i) => ({
  json: {
    resposta:    msg.texto || '',
    tamanho:  msg.tamanho || 'media',
    delay_ms: i === 0 ? 0 : calcDelay(msg.texto || ''),  // Primeira msg sem delay
    indice:   i,
    total:    mensagens.length,
    primeira: i === 0,
    ultima:   i === mensagens.length - 1
  }
}));

return result;

const response = $("Aggregate").first().json;

// 1. Pegamos a lista interna
const listaOriginal = response.data;

// 2. Filtramos para manter apenas a primeira ocorrГӘncia de cada ID
const itensUnicos = listaOriginal.filter((item, index, self) =>
  index === self.findIndex((t) => t.id === item.id)
);

return itensUnicos;
